{
  "name": "FinAI - Intelligent Personal Finance",
  "description": "A modern, AI-powered financial management system for tracking income, expenses, investments, and goals with personalized insights from Gemini.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TransactionType = 'INCOME' | 'EXPENSE';

export enum Category {
  FOOD = 'Alimentação',
  HEALTH = 'Saúde',
  CAR = 'Carro/Transporte',
  FUEL = 'Gasolina',
  TAXES = 'Impostos',
  FIXED_EXPENSE = 'Despesa Fixa',
  VARIABLE_EXPENSE = 'Despesa Variável',
  CREDIT_CARD = 'Cartão de Crédito',
  MARKET = 'Mercado',
  INVESTMENT = 'Investimento',
  SALARY = 'Salário/Receita',
  OTHER = 'Outros'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: Category;
  type: TransactionType;
  isEssential?: boolean;
}

export interface BudgetGoal {
  category: Category;
  limit: number;
}

export interface EmergencyFund {
  target: number;
  current: number;
}

import { GoogleGenAI } from "@google/genai";
import { Transaction } from "../types";

export const getFinancialAdvice = async (transactions: Transaction[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const summary = transactions.reduce((acc, t) => {
    const key = `${t.type}_${t.category}`;
    acc[key] = (acc[key] || 0) + t.amount;
    return acc;
  }, {} as Record<string, number>);

  const prompt = `
    Como um consultor financeiro sênior, analise este resumo mensal e dê 3 dicas práticas e curtas para melhorar a saúde financeira.
    Resumo das transações:
    ${JSON.stringify(summary, null, 2)}

    Responda em Português do Brasil, de forma encorajadora e profissional. 
    Foque em redução de gastos variáveis e aumento de aportes em investimentos.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar dicas no momento. Continue acompanhando seus gastos!";
  } catch (error) {
    console.error("Error fetching Gemini advice:", error);
    return "Mantenha o foco nos seus objetivos financeiros!";
  }
};

import React from 'react';

interface StatCardProps {
  title: string;
  value: number;
  icon: React.ReactNode;
  color: 'emerald' | 'rose' | 'indigo' | 'amber';
  trend?: string;
}

const StatCard: React.FC<StatCardProps> = ({ title, value, icon, color, trend }) => {
  const colors = {
    emerald: 'bg-emerald-50 text-emerald-600',
    rose: 'bg-rose-50 text-rose-600',
    indigo: 'bg-indigo-50 text-indigo-600',
    amber: 'bg-amber-50 text-amber-600',
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-all duration-300">
      <div className="flex items-center justify-between mb-4">
        <div className={`p-3 rounded-xl ${colors[color]}`}>
          {icon}
        </div>
        {trend && (
          <span className={`text-xs font-medium px-2.5 py-1 rounded-full ${trend.startsWith('+') ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
            {trend}
          </span>
        )}
      </div>
      <h3 className="text-slate-500 text-sm font-medium">{title}</h3>
      <p className="text-2xl font-bold text-slate-900 mt-1">
        {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value)}
      </p>
    </div>
  );
};

export default StatCard;

import React, { useState } from 'react';
import { Category, TransactionType, Transaction } from '../types';
import { X, Plus } from 'lucide-react';

interface TransactionFormProps {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  onClose: () => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ onAdd, onClose }) => {
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [type, setType] = useState<TransactionType>('EXPENSE');
  const [category, setCategory] = useState<Category>(Category.OTHER);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    onAdd({
      description,
      amount: parseFloat(amount),
      type,
      category,
      date,
      isEssential: false
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl animate-in fade-in zoom-in duration-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800">Nova Transação</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Descrição</label>
            <input 
              autoFocus
              type="text" 
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="Ex: Aluguel, Salário, Mercado..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Valor</label>
              <input 
                type="number" 
                step="0.01"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                placeholder="0.00"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data</label>
              <input 
                type="date" 
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                required
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tipo</label>
              <select 
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={type}
                onChange={(e) => setType(e.target.value as TransactionType)}
              >
                <option value="EXPENSE">Despesa</option>
                <option value="INCOME">Receita</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Categoria</label>
              <select 
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
              >
                {Object.values(Category).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
          </div>

          <button 
            type="submit" 
            className="w-full py-3 bg-indigo-600 text-white rounded-xl font-semibold hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-2 mt-2"
          >
            <Plus className="w-5 h-5" /> Salvar Transação
          </button>
        </form>
      </div>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Target, 
  Plus, 
  Sparkles,
  LayoutDashboard,
  ArrowUpRight,
  ArrowDownRight,
  Filter,
  RefreshCcw,
  Bot
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { Transaction, Category, EmergencyFund } from './types';
import { CATEGORY_ICONS, INITIAL_TRANSACTIONS } from './constants';
import StatCard from './components/StatCard';
import TransactionForm from './components/TransactionForm';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finai_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [showForm, setShowForm] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<string>('Analizando seu perfil financeiro...');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [emergencyGoal, setEmergencyGoal] = useState<EmergencyFund>({ target: 15000, current: 4200 });

  useEffect(() => {
    localStorage.setItem('finai_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const stats = useMemo(() => {
    const income = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const expenses = transactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const balance = income - expenses;
    const savings = transactions
      .filter(t => t.category === Category.INVESTMENT)
      .reduce((acc, curr) => acc + curr.amount, 0);

    return { income, expenses, balance, savings };
  }, [transactions]);

  const categoryData = useMemo(() => {
    const data: Record<string, number> = {};
    transactions.filter(t => t.type === 'EXPENSE').forEach(t => {
      data[t.category] = (data[t.category] || 0) + t.amount;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [transactions]);

  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substring(2, 9)
    };
    setTransactions(prev => [tx, ...prev]);
  };

  const fetchAdvice = async () => {
    setIsAiLoading(true);
    const advice = await getFinancialAdvice(transactions);
    setAiAdvice(advice);
    setIsAiLoading(false);
  };

  useEffect(() => {
    fetchAdvice();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <Sparkles className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">FinAI</h1>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setShowForm(true)}
              className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-semibold hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-100"
            >
              <Plus className="w-4 h-4" /> Nova Entrada
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {/* Welcome Section */}
        <div className="mb-8">
          <h2 className="text-3xl font-bold text-slate-800">Olá, Douglas Louzada!</h2>
          <p className="text-slate-500 mt-1">Sua saúde financeira está <span className="text-emerald-600 font-semibold">positiva</span> este mês.</p>
        </div>

        {/* Overview Stats */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <StatCard 
            title="Receitas Totais" 
            value={stats.income} 
            icon={<TrendingUp className="w-6 h-6" />} 
            color="emerald" 
            trend="+12.4%"
          />
          <StatCard 
            title="Despesas Totais" 
            value={stats.expenses} 
            icon={<TrendingDown className="w-6 h-6" />} 
            color="rose" 
            trend="-3.2%"
          />
          <StatCard 
            title="Saldo Disponível" 
            value={stats.balance} 
            icon={<Wallet className="w-6 h-6" />} 
            color="indigo" 
          />
          <StatCard 
            title="Investido / Reservas" 
            value={stats.savings} 
            icon={<Target className="w-6 h-6" />} 
            color="amber" 
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Chart Column */}
          <div className="lg:col-span-2 space-y-8">
            {/* Visual Analytics */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex items-center justify-between mb-8">
                <h3 className="text-lg font-bold text-slate-800">Fluxo de Caixa</h3>
                <div className="flex gap-2">
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-slate-50 rounded-lg text-xs font-medium text-slate-500">
                    <div className="w-2 h-2 rounded-full bg-emerald-500" /> Entradas
                  </div>
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-slate-50 rounded-lg text-xs font-medium text-slate-500">
                    <div className="w-2 h-2 rounded-full bg-rose-500" /> Saídas
                  </div>
                </div>
              </div>
              <div className="h-[300px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={categoryData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="name" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: '#94a3b8', fontSize: 12 }} 
                      dy={10}
                    />
                    <YAxis 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: '#94a3b8', fontSize: 12 }} 
                    />
                    <Tooltip 
                      cursor={{ fill: '#f8fafc' }}
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                    />
                    <Bar dataKey="value" radius={[6, 6, 0, 0]} barSize={40}>
                      {categoryData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Recent Transactions */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-bold text-slate-800">Transações Recentes</h3>
                <button className="text-indigo-600 text-sm font-semibold hover:underline flex items-center gap-1">
                  Ver todas <ArrowUpRight className="w-4 h-4" />
                </button>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="text-slate-400 text-xs uppercase tracking-wider font-semibold border-b border-slate-100">
                      <th className="pb-4 font-medium">Descrição</th>
                      <th className="pb-4 font-medium">Categoria</th>
                      <th className="pb-4 font-medium">Data</th>
                      <th className="pb-4 font-medium text-right">Valor</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {transactions.slice(0, 6).map((tx) => (
                      <tr key={tx.id} className="group hover:bg-slate-50/50 transition-colors">
                        <td className="py-4">
                          <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${tx.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-600'}`}>
                              {CATEGORY_ICONS[tx.category]}
                            </div>
                            <span className="font-medium text-slate-800">{tx.description}</span>
                          </div>
                        </td>
                        <td className="py-4 text-sm text-slate-500">{tx.category}</td>
                        <td className="py-4 text-sm text-slate-500">{new Date(tx.date).toLocaleDateString('pt-BR')}</td>
                        <td className={`py-4 text-right font-semibold ${tx.type === 'INCOME' ? 'text-emerald-600' : 'text-slate-900'}`}>
                          {tx.type === 'INCOME' ? '+' : '-'} {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(tx.amount)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          {/* Right Sidebar */}
          <div className="space-y-8">
            {/* AI Advisor Panel */}
            <div className="bg-indigo-900 rounded-2xl p-6 text-white shadow-xl shadow-indigo-200 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <Bot className="w-24 h-24" />
              </div>
              <div className="relative z-10">
                <div className="flex items-center gap-2 mb-4">
                  <div className="w-8 h-8 bg-white/20 rounded-lg flex items-center justify-center">
                    <Sparkles className="w-4 h-4 text-white" />
                  </div>
                  <h3 className="font-bold">FinAI Advisor</h3>
                </div>
                <div className="space-y-4">
                  {isAiLoading ? (
                    <div className="animate-pulse space-y-2">
                      <div className="h-4 bg-white/10 rounded w-3/4"></div>
                      <div className="h-4 bg-white/10 rounded"></div>
                      <div className="h-4 bg-white/10 rounded w-5/6"></div>
                    </div>
                  ) : (
                    <p className="text-indigo-100 text-sm leading-relaxed whitespace-pre-line">
                      {aiAdvice}
                    </p>
                  )}
                  <button 
                    onClick={fetchAdvice}
                    className="flex items-center gap-2 text-xs font-bold text-white bg-indigo-500/30 px-3 py-2 rounded-lg hover:bg-indigo-500/50 transition-colors"
                  >
                    <RefreshCcw className="w-3 h-3" /> Atualizar Dicas
                  </button>
                </div>
              </div>
            </div>

            {/* Allocation Chart */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold text-slate-800 mb-6">Alocação de Gastos</h3>
              <div className="h-[240px]">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={categoryData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                    >
                      {categoryData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip 
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
              <div className="mt-4 space-y-2">
                {categoryData.slice(0, 4).map((item, i) => (
                  <div key={item.name} className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: COLORS[i] }} />
                      <span className="text-slate-600">{item.name}</span>
                    </div>
                    <span className="font-semibold">{Math.round((item.value / stats.expenses) * 100)}%</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Emergency Fund Progress */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-bold text-slate-800">Reserva de Emergência</h3>
                <Target className="w-5 h-5 text-indigo-500" />
              </div>
              <div className="space-y-4">
                <div className="flex justify-between items-end">
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Total Reservado</p>
                    <p className="text-xl font-bold text-slate-900">R$ {emergencyGoal.current.toLocaleString('pt-BR')}</p>
                  </div>
                  <p className="text-sm font-semibold text-indigo-600">
                    {Math.round((emergencyGoal.current / emergencyGoal.target) * 100)}%
                  </p>
                </div>
                <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-indigo-600 rounded-full transition-all duration-1000"
                    style={{ width: `${(emergencyGoal.current / emergencyGoal.target) * 100}%` }}
                  />
                </div>
                <p className="text-xs text-slate-500 italic text-center">
                  Faltam R$ {(emergencyGoal.target - emergencyGoal.current).toLocaleString('pt-BR')} para bater a meta geral!
                </p>
              </div>
            </div>
          </div>
        </div>
      </main>

      {showForm && (
        <TransactionForm 
          onAdd={handleAddTransaction} 
          onClose={() => setShowForm(false)} 
        />
      )}

      {/* Persistent Bottom Nav (Mobile Inspired) */}
      <nav className="lg:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 px-6 py-3 flex justify-between items-center z-50">
        <button className="flex flex-col items-center gap-1 text-indigo-600">
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button 
          onClick={() => setShowForm(true)}
          className="bg-indigo-600 w-12 h-12 rounded-full flex items-center justify-center text-white shadow-lg -mt-8 border-4 border-white active:scale-95 transition-transform"
        >
          <Plus className="w-6 h-6" />
        </button>
        <button className="flex flex-col items-center gap-1 text-slate-400">
          <Filter className="w-6 h-6" />
          <span className="text-[10px] font-bold">Filtros</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Target, 
  Plus, 
  Sparkles,
  LayoutDashboard,
  ArrowUpRight,
  Filter,
  RefreshCcw,
  Bot,
  Calendar,
  Tag,
  XCircle
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { Transaction, Category, EmergencyFund } from './types';
import { CATEGORY_ICONS, INITIAL_TRANSACTIONS } from './constants';
import StatCard from './components/StatCard';
import TransactionForm from './components/TransactionForm';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finai_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [showForm, setShowForm] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<string>('Analizando seu perfil financeiro...');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [emergencyGoal, setEmergencyGoal] = useState<EmergencyFund>({ target: 15000, current: 4200 });

  // Filter States
  const [filterStartDate, setFilterStartDate] = useState<string>('');
  const [filterEndDate, setFilterEndDate] = useState<string>('');
  const [filterCategory, setFilterCategory] = useState<Category | 'ALL'>('ALL');

  useEffect(() => {
    localStorage.setItem('finai_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      const dateMatch = (!filterStartDate || tx.date >= filterStartDate) && 
                        (!filterEndDate || tx.date <= filterEndDate);
      const categoryMatch = filterCategory === 'ALL' || tx.category === filterCategory;
      return dateMatch && categoryMatch;
    });
  }, [transactions, filterStartDate, filterEndDate, filterCategory]);

  const stats = useMemo(() => {
    const income = filteredTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const expenses = filteredTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const balance = income - expenses;
    const savings = filteredTransactions
      .filter(t => t.category === Category.INVESTMENT)
      .reduce((acc, curr) => acc + curr.amount, 0);

    return { income, expenses, balance, savings };
  }, [filteredTransactions]);

  const categoryData = useMemo(() => {
    const data: Record<string, number> = {};
    filteredTransactions.filter(t => t.type === 'EXPENSE').forEach(t => {
      data[t.category] = (data[t.category] || 0) + t.amount;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [filteredTransactions]);

  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substring(2, 9)
    };
    setTransactions(prev => [tx, ...prev]);
  };

  const fetchAdvice = async () => {
    setIsAiLoading(true);
    const advice = await getFinancialAdvice(filteredTransactions);
    setAiAdvice(advice);
    setIsAiLoading(false);
  };

  const clearFilters = () => {
    setFilterStartDate('');
    setFilterEndDate('');
    setFilterCategory('ALL');
  };

  useEffect(() => {
    fetchAdvice();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <Sparkles className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">FinAI</h1>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setShowForm(true)}
              className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-semibold hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-100"
            >
              <Plus className="w-4 h-4" /> Nova Entrada
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {/* Welcome Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <h2 className="text-3xl font-bold text-slate-800">Olá, Douglas Louzada!</h2>
            <p className="text-slate-500 mt-1">Sua saúde financeira está <span className="text-emerald-600 font-semibold">positiva</span> este mês.</p>
          </div>
        </div>

        {/* Filters Section */}
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 mb-8 flex flex-wrap items-center gap-4">
          <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 rounded-xl border border-slate-100">
            <Filter className="w-4 h-4 text-slate-400" />
            <span className="text-sm font-semibold text-slate-700">Filtros</span>
          </div>

          <div className="flex items-center gap-2">
            <Calendar className="w-4 h-4 text-slate-400" />
            <input 
              type="date" 
              className="bg-transparent text-sm outline-none border-b border-transparent focus:border-indigo-500 py-1 transition-all"
              value={filterStartDate}
              onChange={(e) => setFilterStartDate(e.target.value)}
              placeholder="Início"
            />
            <span className="text-slate-300">até</span>
            <input 
              type="date" 
              className="bg-transparent text-sm outline-none border-b border-transparent focus:border-indigo-500 py-1 transition-all"
              value={filterEndDate}
              onChange={(e) => setFilterEndDate(e.target.value)}
              placeholder="Fim"
            />
          </div>

          <div className="h-6 w-px bg-slate-200 hidden md:block" />

          <div className="flex items-center gap-2">
            <Tag className="w-4 h-4 text-slate-400" />
            <select 
              className="bg-transparent text-sm outline-none border-b border-transparent focus:border-indigo-500 py-1 transition-all cursor-pointer"
              value={filterCategory}
              onChange={(e) => setFilterCategory(e.target.value as any)}
            >
              <option value="ALL">Todas as Categorias</option>
              {Object.values(Category).map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
          </div>

          {(filterStartDate || filterEndDate || filterCategory !== 'ALL') && (
            <button 
              onClick={clearFilters}
              className="ml-auto flex items-center gap-1.5 text-xs font-bold text-rose-500 hover:text-rose-600 transition-colors"
            >
              <XCircle className="w-4 h-4" /> Limpar Filtros
            </button>
          )}
        </div>

        {/* Overview Stats */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <StatCard 
            title="Receitas Totais" 
            value={stats.income} 
            icon={<TrendingUp className="w-6 h-6" />} 
            color="emerald" 
          />
          <StatCard 
            title="Despesas Totais" 
            value={stats.expenses} 
            icon={<TrendingDown className="w-6 h-6" />} 
            color="rose" 
          />
          <StatCard 
            title="Saldo Disponível" 
            value={stats.balance} 
            icon={<Wallet className="w-6 h-6" />} 
            color="indigo" 
          />
          <StatCard 
            title="Investido / Reservas" 
            value={stats.savings} 
            icon={<Target className="w-6 h-6" />} 
            color="amber" 
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Chart Column */}
          <div className="lg:col-span-2 space-y-8">
            {/* Visual Analytics */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex items-center justify-between mb-8">
                <h3 className="text-lg font-bold text-slate-800">Resumo por Categoria</h3>
                <div className="flex gap-2">
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-slate-50 rounded-lg text-xs font-medium text-slate-500">
                    <div className="w-2 h-2 rounded-full bg-indigo-500" /> Gastos
                  </div>
                </div>
              </div>
              <div className="h-[300px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={categoryData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="name" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: '#94a3b8', fontSize: 12 }} 
                      dy={10}
                    />
                    <YAxis 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: '#94a3b8', fontSize: 12 }} 
                    />
                    <Tooltip 
                      cursor={{ fill: '#f8fafc' }}
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                    />
                    <Bar dataKey="value" radius={[6, 6, 0, 0]} barSize={40}>
                      {categoryData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Recent Transactions */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-bold text-slate-800">Transações</h3>
                <div className="text-xs text-slate-400 font-medium bg-slate-50 px-2 py-1 rounded">
                  Mostrando {filteredTransactions.length} de {transactions.length}
                </div>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="text-slate-400 text-xs uppercase tracking-wider font-semibold border-b border-slate-100">
                      <th className="pb-4 font-medium">Descrição</th>
                      <th className="pb-4 font-medium">Categoria</th>
                      <th className="pb-4 font-medium">Data</th>
                      <th className="pb-4 font-medium text-right">Valor</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {filteredTransactions.slice(0, 10).map((tx) => (
                      <tr key={tx.id} className="group hover:bg-slate-50/50 transition-colors">
                        <td className="py-4">
                          <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${tx.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-600'}`}>
                              {CATEGORY_ICONS[tx.category]}
                            </div>
                            <span className="font-medium text-slate-800">{tx.description}</span>
                          </div>
                        </td>
                        <td className="py-4 text-sm text-slate-500">{tx.category}</td>
                        <td className="py-4 text-sm text-slate-500">{new Date(tx.date).toLocaleDateString('pt-BR')}</td>
                        <td className={`py-4 text-right font-semibold ${tx.type === 'INCOME' ? 'text-emerald-600' : 'text-slate-900'}`}>
                          {tx.type === 'INCOME' ? '+' : '-'} {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(tx.amount)}
                        </td>
                      </tr>
                    ))}
                    {filteredTransactions.length === 0 && (
                      <tr>
                        <td colSpan={4} className="py-12 text-center text-slate-400 italic">
                          Nenhuma transação encontrada para os filtros aplicados.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          {/* Right Sidebar */}
          <div className="space-y-8">
            {/* AI Advisor Panel */}
            <div className="bg-indigo-900 rounded-2xl p-6 text-white shadow-xl shadow-indigo-200 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <Bot className="w-24 h-24" />
              </div>
              <div className="relative z-10">
                <div className="flex items-center gap-2 mb-4">
                  <div className="w-8 h-8 bg-white/20 rounded-lg flex items-center justify-center">
                    <Sparkles className="w-4 h-4 text-white" />
                  </div>
                  <h3 className="font-bold">FinAI Advisor</h3>
                </div>
                <div className="space-y-4">
                  {isAiLoading ? (
                    <div className="animate-pulse space-y-2">
                      <div className="h-4 bg-white/10 rounded w-3/4"></div>
                      <div className="h-4 bg-white/10 rounded"></div>
                      <div className="h-4 bg-white/10 rounded w-5/6"></div>
                    </div>
                  ) : (
                    <p className="text-indigo-100 text-sm leading-relaxed whitespace-pre-line">
                      {aiAdvice}
                    </p>
                  )}
                  <button 
                    onClick={fetchAdvice}
                    className="flex items-center gap-2 text-xs font-bold text-white bg-indigo-500/30 px-3 py-2 rounded-lg hover:bg-indigo-500/50 transition-colors"
                  >
                    <RefreshCcw className="w-3 h-3" /> Atualizar Dicas
                  </button>
                </div>
              </div>
            </div>

            {/* Allocation Chart */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold text-slate-800 mb-6">Alocação de Gastos</h3>
              <div className="h-[240px]">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={categoryData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                    >
                      {categoryData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip 
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
              <div className="mt-4 space-y-2">
                {categoryData.slice(0, 4).map((item, i) => (
                  <div key={item.name} className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: COLORS[i] }} />
                      <span className="text-slate-600">{item.name}</span>
                    </div>
                    <span className="font-semibold">{Math.round((item.value / stats.expenses) * 100) || 0}%</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Emergency Fund Progress */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-bold text-slate-800">Reserva de Emergência</h3>
                <Target className="w-5 h-5 text-indigo-500" />
              </div>
              <div className="space-y-4">
                <div className="flex justify-between items-end">
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Total Reservado</p>
                    <p className="text-xl font-bold text-slate-900">R$ {emergencyGoal.current.toLocaleString('pt-BR')}</p>
                  </div>
                  <p className="text-sm font-semibold text-indigo-600">
                    {Math.round((emergencyGoal.current / emergencyGoal.target) * 100)}%
                  </p>
                </div>
                <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-indigo-600 rounded-full transition-all duration-1000"
                    style={{ width: `${(emergencyGoal.current / emergencyGoal.target) * 100}%` }}
                  />
                </div>
                <p className="text-xs text-slate-500 italic text-center">
                  Faltam R$ {(emergencyGoal.target - emergencyGoal.current).toLocaleString('pt-BR')} para bater a meta geral!
                </p>
              </div>
            </div>
          </div>
        </div>
      </main>

      {showForm && (
        <TransactionForm 
          onAdd={handleAddTransaction} 
          onClose={() => setShowForm(false)} 
        />
      )}

      {/* Persistent Bottom Nav (Mobile Inspired) */}
      <nav className="lg:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 px-6 py-3 flex justify-between items-center z-50">
        <button className="flex flex-col items-center gap-1 text-indigo-600">
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button 
          onClick={() => setShowForm(true)}
          className="bg-indigo-600 w-12 h-12 rounded-full flex items-center justify-center text-white shadow-lg -mt-8 border-4 border-white active:scale-95 transition-transform"
        >
          <Plus className="w-6 h-6" />
        </button>
        <button className="flex flex-col items-center gap-1 text-slate-400">
          <Filter className="w-6 h-6" />
          <span className="text-[10px] font-bold">Filtros</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Category, TransactionType, Transaction } from '../types';
import { X, Plus } from 'lucide-react';

interface TransactionFormProps {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  onClose: () => void;
  initialData?: Partial<Omit<Transaction, 'id'>>;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ onAdd, onClose, initialData }) => {
  const [description, setDescription] = useState(initialData?.description || '');
  const [amount, setAmount] = useState(initialData?.amount?.toString() || '');
  const [type, setType] = useState<TransactionType>(initialData?.type || 'EXPENSE');
  const [category, setCategory] = useState<Category>(initialData?.category || Category.OTHER);
  const [date, setDate] = useState(initialData?.date || new Date().toISOString().split('T')[0]);

  // Update internal state if initialData changes (though usually handled by mount/unmount)
  useEffect(() => {
    if (initialData) {
      if (initialData.description) setDescription(initialData.description);
      if (initialData.type) setType(initialData.type);
      if (initialData.category) setCategory(initialData.category);
      if (initialData.date) setDate(initialData.date);
      if (initialData.amount) setAmount(initialData.amount.toString());
    }
  }, [initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    onAdd({
      description,
      amount: parseFloat(amount),
      type,
      category,
      date,
      isEssential: false
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl animate-in fade-in zoom-in duration-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800">
            {initialData?.description ? 'Completar Transação' : 'Nova Transação'}
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Descrição</label>
            <input 
              autoFocus={!initialData?.description}
              type="text" 
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="Ex: Aluguel, Salário, Mercado..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Valor</label>
              <input 
                autoFocus={!!initialData?.description}
                type="number" 
                step="0.01"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                placeholder="0.00"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data</label>
              <input 
                type="date" 
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                required
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tipo</label>
              <select 
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={type}
                onChange={(e) => setType(e.target.value as TransactionType)}
              >
                <option value="EXPENSE">Despesa</option>
                <option value="INCOME">Receita</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Categoria</label>
              <select 
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
              >
                {Object.values(Category).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
          </div>

          <button 
            type="submit" 
            className="w-full py-3 bg-indigo-600 text-white rounded-xl font-semibold hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-2 mt-2"
          >
            <Plus className="w-5 h-5" /> Salvar Transação
          </button>
        </form>
      </div>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Target, 
  Plus, 
  Sparkles,
  LayoutDashboard,
  ArrowUpRight,
  Filter,
  RefreshCcw,
  Bot,
  Calendar,
  Tag,
  XCircle,
  Clock,
  Home,
  Receipt,
  DollarSign
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { Transaction, Category, EmergencyFund } from './types';
import { CATEGORY_ICONS, INITIAL_TRANSACTIONS } from './constants';
import StatCard from './components/StatCard';
import TransactionForm from './components/TransactionForm';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finai_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [showForm, setShowForm] = useState(false);
  const [formInitialData, setFormInitialData] = useState<Partial<Omit<Transaction, 'id'>> | undefined>(undefined);
  const [aiAdvice, setAiAdvice] = useState<string>('Analizando seu perfil financeiro...');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [emergencyGoal, setEmergencyGoal] = useState<EmergencyFund>({ target: 15000, current: 4200 });

  // Filter States
  const [filterStartDate, setFilterStartDate] = useState<string>('');
  const [filterEndDate, setFilterEndDate] = useState<string>('');
  const [filterCategory, setFilterCategory] = useState<Category | 'ALL'>('ALL');

  useEffect(() => {
    localStorage.setItem('finai_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      const dateMatch = (!filterStartDate || tx.date >= filterStartDate) && 
                        (!filterEndDate || tx.date <= filterEndDate);
      const categoryMatch = filterCategory === 'ALL' || tx.category === filterCategory;
      return dateMatch && categoryMatch;
    });
  }, [transactions, filterStartDate, filterEndDate, filterCategory]);

  const stats = useMemo(() => {
    const income = filteredTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const expenses = filteredTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const balance = income - expenses;
    const savings = filteredTransactions
      .filter(t => t.category === Category.INVESTMENT)
      .reduce((acc, curr) => acc + curr.amount, 0);

    return { income, expenses, balance, savings };
  }, [filteredTransactions]);

  const categoryData = useMemo(() => {
    const data: Record<string, number> = {};
    filteredTransactions.filter(t => t.type === 'EXPENSE').forEach(t => {
      data[t.category] = (data[t.category] || 0) + t.amount;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [filteredTransactions]);

  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substring(2, 9)
    };
    setTransactions(prev => [tx, ...prev]);
  };

  const openFormWithData = (data: Partial<Omit<Transaction, 'id'>>) => {
    setFormInitialData(data);
    setShowForm(true);
  };

  const openEmptyForm = () => {
    setFormInitialData(undefined);
    setShowForm(true);
  };

  const fetchAdvice = async () => {
    setIsAiLoading(true);
    const advice = await getFinancialAdvice(filteredTransactions);
    setAiAdvice(advice);
    setIsAiLoading(false);
  };

  const clearFilters = () => {
    setFilterStartDate('');
    setFilterEndDate('');
    setFilterCategory('ALL');
  };

  useEffect(() => {
    fetchAdvice();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

  const quickActions = [
    {
      label: 'Despesa Fixa',
      icon: <Home className="w-5 h-5" />,
      color: 'bg-slate-100 text-slate-700',
