    },
    {
      label: 'Receita Extra',
      icon: <DollarSign className="w-5 h-5" />,
      color: 'bg-emerald-50 text-emerald-600',
      data: { type: 'INCOME', category: Category.SALARY, description: 'Receita Extra' }
    },
    {
      label: 'Lembrete de Imposto',
      icon: <Receipt className="w-5 h-5" />,
      color: 'bg-amber-50 text-amber-600',
      data: { type: 'EXPENSE', category: Category.TAXES, description: 'Pagamento de Imposto' }
    },
    {
      label: 'Gasto no Mercado',
      icon: <Clock className="w-5 h-5" />,
      color: 'bg-indigo-50 text-indigo-600',
      data: { type: 'EXPENSE', category: Category.MARKET, description: 'Mercado Semanal' }
    }
  ];

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <Sparkles className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">FinAI</h1>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={openEmptyForm}
              className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-semibold hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-100"
            >
              <Plus className="w-4 h-4" /> Nova Entrada
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {/* Welcome Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <h2 className="text-3xl font-bold text-slate-800">Olá, Douglas Louzada!</h2>
            <p className="text-slate-500 mt-1">Sua saúde financeira está <span className="text-emerald-600 font-semibold">positiva</span> este mês.</p>
          </div>
        </div>

        {/* Filters Section */}
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 mb-8 flex flex-wrap items-center gap-4">
          <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 rounded-xl border border-slate-100">
            <Filter className="w-4 h-4 text-slate-400" />
            <span className="text-sm font-semibold text-slate-700">Filtros</span>
          </div>

          <div className="flex items-center gap-2">
            <Calendar className="w-4 h-4 text-slate-400" />
            <input 
              type="date" 
              className="bg-transparent text-sm outline-none border-b border-transparent focus:border-indigo-500 py-1 transition-all"
              value={filterStartDate}
              onChange={(e) => setFilterStartDate(e.target.value)}
              placeholder="Início"
            />
            <span className="text-slate-300">até</span>
            <input 
              type="date" 
              className="bg-transparent text-sm outline-none border-b border-transparent focus:border-indigo-500 py-1 transition-all"
              value={filterEndDate}
              onChange={(e) => setFilterEndDate(e.target.value)}
