import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Target, 
  Plus, 
  Sparkles,
  LayoutDashboard,
  ArrowUpRight,
  Filter,
  RefreshCcw,
  Bot,
  Calendar,
  Tag,
  XCircle,
  Clock,
  Home,
  Receipt,
  DollarSign,
  Settings2,
  ChevronRight,
  BarChart3,
  PieChart as PieChartIcon,
  ArrowRightLeft
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip as RechartsTooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { Tooltip } from 'react-tooltip';
import { Transaction, Category, EmergencyFund } from './types';
import { CATEGORY_ICONS, INITIAL_TRANSACTIONS } from './constants';
import StatCard from './components/StatCard';
import TransactionForm from './components/TransactionForm';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finai_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });

  const [showForm, setShowForm] = useState(false);
  const [showGoalModal, setShowGoalModal] = useState(false);
  const [formInitialData, setFormInitialData] = useState<Partial<Omit<Transaction, 'id'>> | undefined>(undefined);
  const [aiAdvice, setAiAdvice] = useState<string>('Analizando seu perfil financeiro...');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const [emergencyGoal, setEmergencyGoal] = useState<EmergencyFund>(() => {
    const saved = localStorage.getItem('finai_goal');
    return saved ? JSON.parse(saved) : { target: 15000, current: 0 };
  });

  const [newGoalValue, setNewGoalValue] = useState(emergencyGoal.target.toString());

  // Filter States
  const [filterStartDate, setFilterStartDate] = useState<string>('');
  const [filterEndDate, setFilterEndDate] = useState<string>('');
  const [filterCategory, setFilterCategory] = useState<Category | 'ALL'>('ALL');

  useEffect(() => {
    localStorage.setItem('finai_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('finai_goal', JSON.stringify(emergencyGoal));
  }, [emergencyGoal]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      const dateMatch = (!filterStartDate || tx.date >= filterStartDate) && 
                        (!filterEndDate || tx.date <= filterEndDate);
      const categoryMatch = filterCategory === 'ALL' || tx.category === filterCategory;
      return dateMatch && categoryMatch;
    });
  }, [transactions, filterStartDate, filterEndDate, filterCategory]);

  const { stats, categoryData, currentMonthInvestments } = useMemo(() => {
    let income = 0;
    let expenses = 0;
    let savings = 0;
    const expenseCategoryMap: Record<string, number> = {};

    filteredTransactions.forEach(t => {
      if (t.type === 'INCOME') {
        income += t.amount;
      } else {
        expenses += t.amount;
        expenseCategoryMap[t.category] = (expenseCategoryMap[t.category] || 0) + t.amount;
      }
      if (t.category === Category.INVESTMENT) {
        savings += t.amount;
      }
    });

    const categoryArray = Object.entries(expenseCategoryMap)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);

    return {
      stats: { income, expenses, balance: income - expenses, savings },
      categoryData: categoryArray,
      currentMonthInvestments: savings
    };
  }, [filteredTransactions]);

  // Logic to calculate historical monthly reports
  const monthlyReports = useMemo(() => {
    const reports: Record<string, { income: number; expenses: number; investments: number; categories: Record<string, number> }> = {};

    transactions.forEach(t => {
      const monthKey = t.date.substring(0, 7); // YYYY-MM
      if (!reports[monthKey]) {
        reports[monthKey] = { income: 0, expenses: 0, investments: 0, categories: {} };
      }

      if (t.type === 'INCOME') {
        reports[monthKey].income += t.amount;
      } else {
        reports[monthKey].expenses += t.amount;
        reports[monthKey].categories[t.category] = (reports[monthKey].categories[t.category] || 0) + t.amount;
      }

      if (t.category === Category.INVESTMENT) {
        reports[monthKey].investments += t.amount;
      }
    });

    return Object.entries(reports)
      .sort((a, b) => b[0].localeCompare(a[0])) // Most recent month first
      .map(([month, data]) => ({ month, ...data }));
  }, [transactions]);

  // Update "current" in emergency goal based on total historical investments
  useEffect(() => {
    const totalInvested = transactions
      .filter(t => t.category === Category.INVESTMENT)
      .reduce((acc, curr) => acc + curr.amount, 0);
    setEmergencyGoal(prev => ({ ...prev, current: totalInvested }));
  }, [transactions]);

  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substring(2, 9)
    };
    setTransactions(prev => [tx, ...prev]);
  };

  const handleUpdateGoal = () => {
    const val = parseFloat(newGoalValue);
    if (!isNaN(val) && val > 0) {
      setEmergencyGoal(prev => ({ ...prev, target: val }));
      setShowGoalModal(false);
    }
  };

  const openFormWithData = (data: Partial<Omit<Transaction, 'id'>>) => {
    setFormInitialData(data);
    setShowForm(true);
  };

  const openEmptyForm = () => {
    setFormInitialData(undefined);
    setShowForm(true);
  };

  const fetchAdvice = async () => {
    setIsAiLoading(true);
    const advice = await getFinancialAdvice(filteredTransactions);
    setAiAdvice(advice);
    setIsAiLoading(false);
  };

  const clearFilters = () => {
    setFilterStartDate('');
    setFilterEndDate('');
    setFilterCategory('ALL');
  };

  useEffect(() => {
    fetchAdvice();
  }, []);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

  const quickActions = [
    {
      label: 'Despesa Fixa',
      icon: <Home className="w-5 h-5" />,
      color: 'bg-slate-100 text-slate-700',
      data: { type: 'EXPENSE', category: Category.FIXED_EXPENSE, description: 'Aluguel / Condomínio' }
    },
    {
      label: 'Receita Extra',
      icon: <DollarSign className="w-5 h-5" />,
      color: 'bg-emerald-50 text-emerald-600',
      data: { type: 'INCOME', category: Category.SALARY, description: 'Receita Extra' }
    },
    {
      label: 'Lembrete de Imposto',
      icon: <Receipt className="w-5 h-5" />,
      color: 'bg-amber-50 text-amber-600',
      data: { type: 'EXPENSE', category: Category.TAXES, description: 'Pagamento de Imposto' }
    },
    {
      label: 'Gasto no Mercado',
      icon: <Clock className="w-5 h-5" />,
      color: 'bg-indigo-50 text-indigo-600',
      data: { type: 'EXPENSE', category: Category.MARKET, description: 'Mercado Semanal' }
    }
  ];

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      <Tooltip id="main-tooltip" style={{ borderRadius: '8px', fontSize: '12px', zIndex: 100 }} />

      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <Sparkles className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">FinAI</h1>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={openEmptyForm}
              className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-semibold hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-100"
            >
              <Plus className="w-4 h-4" /> Nova Entrada
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {/* Welcome Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <h2 className="text-3xl font-bold text-slate-800">Olá, Douglas Louzada!</h2>
            <p className="text-slate-500 mt-1">Sua saúde financeira está <span className="text-emerald-600 font-semibold">positiva</span> este mês.</p>
          </div>
        </div>

        {/* Filters Section */}
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 mb-8 flex flex-wrap items-center gap-4">
          <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 rounded-xl border border-slate-100">
            <Filter className="w-4 h-4 text-slate-400" />
            <span className="text-sm font-semibold text-slate-700">Filtros</span>
          </div>

          <div className="flex items-center gap-2">
            <Calendar className="w-4 h-4 text-slate-400" />
            <input 
              type="date" 
              className="bg-transparent text-sm outline-none border-b border-transparent focus:border-indigo-500 py-1 transition-all"
              value={filterStartDate}
              onChange={(e) => setFilterStartDate(e.target.value)}
              placeholder="Início"
            />
            <span className="text-slate-300">até</span>
            <input 
              type="date" 
              className="bg-transparent text-sm outline-none border-b border-transparent focus:border-indigo-500 py-1 transition-all"
              value={filterEndDate}
              onChange={(e) => setFilterEndDate(e.target.value)}
              placeholder="Fim"
            />
          </div>

          <div className="h-6 w-px bg-slate-200 hidden md:block" />

          <div className="flex items-center gap-2">
            <Tag className="w-4 h-4 text-slate-400" />
            <select 
