                    />
                    <Legend verticalAlign="top" height={36}/>
                    <Area type="monotone" dataKey="income" name="Receita" stroke="#10b981" fillOpacity={1} fill="url(#colorIncome)" strokeWidth={3} />
                    <Area type="monotone" dataKey="expenses" name="Despesa" stroke="#f43f5e" fillOpacity={1} fill="url(#colorExpense)" strokeWidth={3} />
                    <Area type="monotone" dataKey="investments" name="Investido" stroke="#6366f1" fillOpacity={0} strokeWidth={3} strokeDasharray="5 5" />
