                <div className="space-y-3">
                  {latestMonthsReports.map((report) => (
                    <button
                      key={report.month}
                      onClick={() => setSelectedReportMonth(report.month)}
                      className={`w-full p-5 rounded-2xl border transition-all flex items-center justify-between text-left group ${selectedReportMonth === report.month ? 'bg-indigo-50 border-indigo-200 shadow-sm' : 'bg-slate-50 border-transparent hover:bg-white hover:border-slate-200'}`}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-sm ${selectedReportMonth === report.month ? 'bg-indigo-600 text-white' : 'bg-white text-slate-500 shadow-sm'}`}>
                          {new Date(report.month + '-01').toLocaleDateString('pt-BR', { month: 'short' }).toUpperCase().replace('.', '')}
                        </div>
                        <div>
                          <p className="font-bold text-slate-800">{new Date(report.month + '-01').toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}</p>
                          <div className="flex gap-3 mt-1">
                            <span className="text-[10px] font-bold text-emerald-600 uppercase">Salário: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(report.income)}</span>
                            <span className="text-[10px] font-bold text-rose-500 uppercase">Gasto: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(report.expenses)}</span>
                          </div>
                        </div>
                      </div>
                      <div className="text-right flex flex-col items-end">
                        <div className="flex items-center gap-1.5 text-indigo-600 font-black text-sm mb-1">
