                          {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(report.investments)}
                        </div>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest group-hover:text-indigo-500">Ver detalhes</p>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Detailed Month Analysis */}
              <div className="space-y-8">
                {selectedReportMonth && selectedMonthData ? (
                  <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 animate-in fade-in zoom-in-95 duration-300">
                    <div className="flex items-center justify-between mb-8">
                      <div>
                        <h3 className="text-2xl font-black text-slate-800">{new Date(selectedReportMonth + '-01').toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}</h3>
                        <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Breakdown de Categorias e Aportes</p>
                      </div>
                      <div className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl border border-indigo-100">
                         <Briefcase className="w-6 h-6" />
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4 mb-8">
                      <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Taxa de Poupança</p>
                        <p className="text-xl font-black text-slate-800">
                          {/* Add explicit type assertions to fix arithmetic errors on selectedMonthData properties */}
                          {Math.round(((selectedMonthData.investments as number) / (selectedMonthData.income as number)) * 100) || 0}%
                        </p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Saldo Líquido</p>
                        <p className={`text-xl font-black ${(selectedMonthData.income as number) - (selectedMonthData.expenses as number) >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                          {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format((selectedMonthData.income as number) - (selectedMonthData.expenses as number))}
                        </p>
                      </div>
                    </div>

                    <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Gasto por Categoria</h4>
                    <div className="space-y-3">
                      {/* Cast Object.entries result to handle unknown/loosely typed categories record */}
                      {(Object.entries(selectedMonthData.categories) as [string, number][])
                        .sort((a, b) => (b[1] as number) - (a[1] as number))
                        .map(([cat, val], i) => (
                          <div key={cat} className="flex items-center justify-between group">
                            <div className="flex items-center gap-3">
                              <div className="w-8 h-8 rounded-lg flex items-center justify-center bg-slate-50 text-slate-500 border border-slate-100 transition-colors group-hover:bg-indigo-600 group-hover:text-white">
                                {CATEGORY_ICONS[cat as Category]}
                              </div>
                              <span className="text-sm font-bold text-slate-700">{cat}</span>
                            </div>
                            <div className="text-right">
                              {/* Use type assertion for val to ensure compatibility with NumberFormat.format */}
                              <p className="text-sm font-black text-slate-800">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val as number)}</p>
                              <div className="w-24 h-1.5 bg-slate-100 rounded-full mt-1 overflow-hidden">
                                <div 
                                  className="h-full bg-indigo-500 rounded-full" 
                                  style={{ width: `${((val as number) / (selectedMonthData.expenses as number)) * 100}%` }}
                                />
                              </div>
                            </div>
                          </div>
                        ))}
                    </div>
                  </div>
                ) : (
                  <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl p-12 text-center h-full flex flex-col items-center justify-center">
                    <History className="w-12 h-12 text-slate-300 mb-4" />
                    <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Selecione um mês para ver a análise detalhada</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Forms & Modals */}
      {showForm && (
        <TransactionForm 
          onAdd={handleAddTransaction} 
          onClose={() => {
            setShowForm(false);
            setFormInitialData(undefined);
          }} 
          initialData={formInitialData}
        />
      )}

      {showGoalModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-3xl w-full max-w-sm p-8 shadow-2xl scale-in-center">
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Ajustar Meta</h2>
            <p className="text-slate-500 text-sm mb-6 leading-relaxed">Defina o montante ideal para sua reserva ou investimento total acumulado.</p>
            <div className="space-y-4">
              <div className="relative">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Novo Valor Alvo (R$)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">R$</span>
                  <input 
                    type="number" 
                    value={newGoalValue}
                    onChange={(e) => setNewGoalValue(e.target.value)}
                    className="w-full pl-12 pr-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-xl font-black text-indigo-600 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all"
                    placeholder="0.00"
                  />
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button 
                  onClick={() => setShowGoalModal(false)}
                  className="flex-1 py-4 text-slate-500 font-black uppercase text-xs tracking-widest hover:bg-slate-50 rounded-2xl transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  onClick={handleUpdateGoal}
                  className="flex-1 py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
                >
                  Confirmar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Persistent Bottom Nav (Mobile Only) */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 px-6 py-3 flex justify-between items-center z-50">
        <button 
          onClick={() => setActiveTab('overview')}
          className={`flex flex-col items-center gap-1 ${activeTab === 'overview' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-[10px] font-bold">Dashboard</span>
        </button>
        <button 
          onClick={openEmptyForm}
          className="bg-indigo-600 w-12 h-12 rounded-full flex items-center justify-center text-white shadow-lg -mt-8 border-4 border-white active:scale-95 transition-transform"
        >
          <Plus className="w-6 h-6" />
        </button>
        <button 
          onClick={() => setActiveTab('reports')}
          className={`flex flex-col items-center gap-1 ${activeTab === 'reports' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <BarChart3 className="w-6 h-6" />
          <span className="text-[10px] font-bold">Relatórios</span>
        </button>
      </nav>

      <style>{`
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
        .animate-shimmer {
          animation: shimmer 2s infinite;
        }
        .scale-in-center {
          animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both;
        }
        @keyframes scale-in-center {
          0% { transform: scale(0.9); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Target, 
  Plus, 
  Sparkles,
  LayoutDashboard,
  Filter,
  RefreshCcw,
  Bot,
  Calendar,
  Tag,
  XCircle,
  Clock,
  Home,
  Receipt,
  DollarSign,
  Settings2,
  BarChart3,
  PieChart as PieChartIcon,
  ArrowRightLeft,
  ChevronDown,
  History,
  Briefcase,
  Moon,
  Sun
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip as RechartsTooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie,
  LineChart,
  Line,
  Legend,
  AreaChart,
  Area
} from 'recharts';
import { Tooltip } from 'react-tooltip';
import { Transaction, Category, EmergencyFund } from './types';
import { CATEGORY_ICONS, INITIAL_TRANSACTIONS } from './constants';
import StatCard from './components/StatCard';
import TransactionForm from './components/TransactionForm';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(() => {
    const saved = localStorage.getItem('finai_theme');
    return saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finai_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });

  const [showForm, setShowForm] = useState(false);
  const [showGoalModal, setShowGoalModal] = useState(false);
  const [activeTab, setActiveTab] = useState<'overview' | 'reports'>('overview');
  const [selectedReportMonth, setSelectedReportMonth] = useState<string | null>(null);
  const [formInitialData, setFormInitialData] = useState<Partial<Omit<Transaction, 'id'>> | undefined>(undefined);
  const [aiAdvice, setAiAdvice] = useState<string>('Analizando seu perfil financeiro...');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const [emergencyGoal, setEmergencyGoal] = useState<EmergencyFund>(() => {
    const saved = localStorage.getItem('finai_goal');
    return saved ? JSON.parse(saved) : { target: 15000, current: 0 };
  });

  const [newGoalValue, setNewGoalValue] = useState(emergencyGoal.target.toString());

  // Filter States
  const [filterStartDate, setFilterStartDate] = useState<string>('');
  const [filterEndDate, setFilterEndDate] = useState<string>('');
  const [filterCategory, setFilterCategory] = useState<Category | 'ALL'>('ALL');

  useEffect(() => {
    localStorage.setItem('finai_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('finai_goal', JSON.stringify(emergencyGoal));
  }, [emergencyGoal]);

  useEffect(() => {
    localStorage.setItem('finai_theme', darkMode ? 'dark' : 'light');
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      const dateMatch = (!filterStartDate || tx.date >= filterStartDate) && 
                        (!filterEndDate || tx.date <= filterEndDate);
      const categoryMatch = filterCategory === 'ALL' || tx.category === filterCategory;
      return dateMatch && categoryMatch;
    });
  }, [transactions, filterStartDate, filterEndDate, filterCategory]);

  const { stats, categoryData } = useMemo(() => {
    let income = 0;
    let expenses = 0;
    let savings = 0;
    const expenseCategoryMap: Record<string, number> = {};

    filteredTransactions.forEach(t => {
      if (t.type === 'INCOME') {
        income += t.amount;
      } else {
        expenses += t.amount;
        expenseCategoryMap[t.category] = (expenseCategoryMap[t.category] || 0) + t.amount;
      }
      if (t.category === Category.INVESTMENT) {
        savings += t.amount;
      }
    });

    const categoryArray = Object.entries(expenseCategoryMap)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);

    return {
      stats: { income, expenses, balance: income - expenses, savings },
      categoryData: categoryArray
    };
  }, [filteredTransactions]);

  // Historical Monthly Analytics
  const monthlyReports = useMemo(() => {
    const reports: Record<string, { income: number; expenses: number; investments: number; categories: Record<string, number> }> = {};

    transactions.forEach(t => {
      const monthKey = t.date.substring(0, 7); // YYYY-MM
      if (!reports[monthKey]) {
        reports[monthKey] = { income: 0, expenses: 0, investments: 0, categories: {} };
      }

      if (t.type === 'INCOME') {
        reports[monthKey].income += t.amount;
      } else {
        reports[monthKey].expenses += t.amount;
        reports[monthKey].categories[t.category] = (reports[monthKey].categories[t.category] || 0) + t.amount;
      }

      if (t.category === Category.INVESTMENT) {
        reports[monthKey].investments += t.amount;
      }
    });

    return Object.entries(reports)
      .sort((a, b) => a[0].localeCompare(b[0])) // Chronological for charts
      .map(([month, data]) => ({ month, ...data }));
  }, [transactions]);

  const latestMonthsReports = useMemo(() => [...monthlyReports].reverse(), [monthlyReports]);

  // Update current invested amount
  useEffect(() => {
    const totalInvested = transactions
      .filter(t => t.category === Category.INVESTMENT)
      .reduce((acc, curr) => acc + curr.amount, 0);
    setEmergencyGoal(prev => ({ ...prev, current: totalInvested }));
  }, [transactions]);

  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substring(2, 9)
    };
    setTransactions(prev => [tx, ...prev]);
  };

  const handleUpdateGoal = () => {
    const val = parseFloat(newGoalValue);
    if (!isNaN(val) && val > 0) {
      setEmergencyGoal(prev => ({ ...prev, target: val }));
      setShowGoalModal(false);
    }
  };

  const openFormWithData = (data: Partial<Omit<Transaction, 'id'>>) => {
    setFormInitialData(data);
    setShowForm(true);
  };

  const openEmptyForm = () => {
    setFormInitialData(undefined);
    setShowForm(true);
  };

  const fetchAdvice = async () => {
    setIsAiLoading(true);
    const advice = await getFinancialAdvice(filteredTransactions);
    setAiAdvice(advice);
    setIsAiLoading(false);
  };

  const clearFilters = () => {
    setFilterStartDate('');
    setFilterEndDate('');
    setFilterCategory('ALL');
  };

  useEffect(() => {
    fetchAdvice();
  }, []);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

  const quickActions = [
    {
      label: 'Despesa Fixa',
      icon: <Home className="w-5 h-5" />,
      color: 'bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-300',
      data: { type: 'EXPENSE', category: Category.FIXED_EXPENSE, description: 'Aluguel / Condomínio' }
    },
    {
      label: 'Receita Extra',
      icon: <DollarSign className="w-5 h-5" />,
      color: 'bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400',
      data: { type: 'INCOME', category: Category.SALARY, description: 'Receita Extra' }
    },
    {
      label: 'Lembrete de Imposto',
      icon: <Receipt className="w-5 h-5" />,
      color: 'bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400',
      data: { type: 'EXPENSE', category: Category.TAXES, description: 'Pagamento de Imposto' }
    },
    {
      label: 'Investimento',
      icon: <TrendingUp className="w-5 h-5" />,
      color: 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400',
      data: { type: 'EXPENSE', category: Category.INVESTMENT, description: 'Aporte Mensal' }
    }
  ];

  const selectedMonthData = useMemo(() => {
    if (!selectedReportMonth) return null;
    return monthlyReports.find(r => r.month === selectedReportMonth);
  }, [selectedReportMonth, monthlyReports]);

  return (
    <div className={`min-h-screen transition-colors duration-300 ${darkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'} pb-20`}>
      <Tooltip id="main-tooltip" style={{ borderRadius: '8px', fontSize: '12px', zIndex: 100 }} />

      {/* Header */}
      <header className={`sticky top-0 z-40 backdrop-blur-md border-b transition-colors duration-300 ${darkMode ? 'bg-slate-900/80 border-slate-800' : 'bg-white/80 border-slate-200'}`}>
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <Sparkles className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">FinAI</h1>
          </div>

          <nav className={`hidden md:flex items-center gap-1 p-1 rounded-xl transition-colors ${darkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
            <button 
              onClick={() => setActiveTab('overview')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'overview' ? (darkMode ? 'bg-slate-700 text-indigo-400 shadow-sm' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500 hover:text-slate-400'}`}
            >
              Visão Geral
            </button>
            <button 
              onClick={() => setActiveTab('reports')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'reports' ? (darkMode ? 'bg-slate-700 text-indigo-400 shadow-sm' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500 hover:text-slate-400'}`}
            >
              Relatórios
            </button>
          </nav>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className={`p-2 rounded-xl transition-colors ${darkMode ? 'bg-slate-800 text-amber-400 hover:bg-slate-700' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
              aria-label="Toggle Theme"
            >
              {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <button 
              onClick={openEmptyForm}
              className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-semibold hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-100 dark:shadow-none"
            >
              <Plus className="w-4 h-4" /> Nova Entrada
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {activeTab === 'overview' ? (
          <>
            {/* Overview Tab Content */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
              <div>
                <h2 className={`text-3xl font-bold ${darkMode ? 'text-slate-100' : 'text-slate-800'}`}>Painel Financeiro</h2>
                <p className="text-slate-500 mt-1">Acompanhe seu fluxo de caixa e progresso de metas.</p>
              </div>
            </div>

