                    <defs>
                      <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/><stop offset="95%" stopColor="#10b981" stopOpacity={0}/></linearGradient>
                      <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#f43f5e" stopOpacity={0.1}/><stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/></linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={darkMode ? "#1e293b" : "#f1f5f9"} />
                    <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 9 }} tickFormatter={(val) => new Date(val + '-01').toLocaleDateString('pt-BR', { month: 'short' })} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 9 }} hide={window.innerWidth < 640} />
                    <RechartsTooltip contentStyle={{ borderRadius: '12px', fontSize: '10px', backgroundColor: darkMode ? '#1e293b' : '#fff' }} labelFormatter={(val) => new Date(val + '-01').toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })} />
                    <Area type="monotone" dataKey="income" name="Receita" stroke="#10b981" fillOpacity={1} fill="url(#colorIncome)" strokeWidth={2} />
                    <Area type="monotone" dataKey="expenses" name="Despesa" stroke="#f43f5e" fillOpacity={1} fill="url(#colorExpense)" strokeWidth={2} />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
              {/* Month List */}
              <div className={`p-5 md:p-6 rounded-2xl md:rounded-3xl shadow-sm border transition-colors duration-300 ${darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
                <h3 className={`text-lg md:text-xl font-bold mb-4 md:mb-6 flex items-center gap-2 ${darkMode ? 'text-slate-100' : 'text-slate-800'}`}>
                  <History className="w-5 h-5 text-indigo-500" /> Histórico
                </h3>
                <div className="space-y-2 md:space-y-3">
                  {latestMonthsReports.map((report) => (
                    <button
                      key={report.month}
                      onClick={() => setSelectedReportMonth(report.month)}
                      className={`w-full p-4 rounded-xl border transition-all flex items-center justify-between text-left group ${selectedReportMonth === report.month ? (darkMode ? 'bg-slate-800 border-indigo-500/30' : 'bg-indigo-50 border-indigo-200 shadow-sm') : (darkMode ? 'bg-slate-800/40 border-transparent hover:bg-slate-800 hover:border-slate-700' : 'bg-slate-50 border-transparent hover:bg-white hover:border-slate-200')}`}
                    >
                      <div className="flex items-center gap-3">
                        <div className={`w-10 h-10 rounded-lg flex items-center justify-center font-bold text-[10px] ${selectedReportMonth === report.month ? 'bg-indigo-600 text-white' : (darkMode ? 'bg-slate-700 text-slate-400' : 'bg-white text-slate-500 shadow-sm')}`}>
                          {new Date(report.month + '-01').toLocaleDateString('pt-BR', { month: 'short' }).toUpperCase().replace('.', '')}
                        </div>
                        <div>
                          <p className={`font-bold text-xs md:text-sm ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}>{new Date(report.month + '-01').toLocaleDateString('pt-BR', { month: 'long' })}</p>
                          <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-tighter">Saldo: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(report.income - report.expenses)}</p>
                        </div>
                      </div>
                      <div className="text-right">
                         <ChevronDown className={`w-4 h-4 transition-transform ${selectedReportMonth === report.month ? 'rotate-180' : ''}`} />
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Detailed Month Analysis */}
              <div className="space-y-6 md:space-y-8">
                {selectedReportMonth && selectedMonthData ? (
                  <div className={`p-5 md:p-8 rounded-2xl md:rounded-3xl shadow-sm border transition-colors duration-300 animate-in fade-in zoom-in-95 ${darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
                    <div className="flex items-center justify-between mb-6">
                      <h3 className={`text-lg md:text-xl font-black ${darkMode ? 'text-slate-100' : 'text-slate-800'}`}>{new Date(selectedReportMonth + '-01').toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}</h3>
                    </div>

                    <div className="grid grid-cols-2 gap-3 mb-6">
                      <div className={`p-3 rounded-xl border transition-colors ${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
                        <p className="text-[8px] font-bold text-slate-400 uppercase mb-1">Poupança</p>
                        <p className={`text-base font-black ${darkMode ? 'text-slate-100' : 'text-slate-800'}`}>{Math.round(((selectedMonthData.investments as number) / (selectedMonthData.income as number)) * 100) || 0}%</p>
                      </div>
                      <div className={`p-3 rounded-xl border transition-colors ${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
                        <p className="text-[8px] font-bold text-slate-400 uppercase mb-1">Saldo</p>
                        <p className={`text-base font-black ${(selectedMonthData.income as number) - (selectedMonthData.expenses as number) >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format((selectedMonthData.income as number) - (selectedMonthData.expenses as number))}</p>
                      </div>
                    </div>

                    <div className="space-y-2.5">
                      {(Object.entries(selectedMonthData.categories) as [string, number][])
                        .sort((a, b) => (b[1] as number) - (a[1] as number))
                        .slice(0, 6)
                        .map(([cat, val]) => (
                          <div key={cat} className="flex items-center justify-between group">
                            <div className="flex items-center gap-2">
                              <div className={`w-7 h-7 rounded-lg flex items-center justify-center border ${darkMode ? 'bg-slate-800 text-slate-500 border-slate-700' : 'bg-slate-50 text-slate-500 border-slate-100'}`}>
                                {CATEGORY_ICONS[cat as Category]}
                              </div>
                              <span className={`text-[10px] font-bold truncate max-w-[80px] ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>{cat}</span>
                            </div>
                            <div className="text-right flex items-center gap-3">
                              <p className={`text-[10px] font-black ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}>{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val as number)}</p>
                              <div className={`w-12 md:w-20 h-1.5 rounded-full overflow-hidden hidden xs:block ${darkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                                <div className="h-full bg-indigo-500 rounded-full" style={{ width: `${((val as number) / (selectedMonthData.expenses as number)) * 100}%` }} />
                              </div>
                            </div>
                          </div>
                        ))}
                    </div>
                  </div>
                ) : (
                  <div className={`border-2 border-dashed rounded-2xl md:rounded-3xl p-10 text-center flex flex-col items-center justify-center transition-colors duration-300 ${darkMode ? 'bg-slate-900/40 border-slate-800' : 'bg-slate-50 border-slate-200'}`}>
                    <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Selecione um mês no histórico</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Forms & Modals */}
      {showForm && (
        <TransactionForm 
          onAdd={handleAddTransaction} 
          onClose={() => { setShowForm(false); setFormInitialData(undefined); }} 
          initialData={formInitialData}
        />
      )}

      {showGoalModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
          <div className={`rounded-2xl md:rounded-3xl w-full max-w-xs p-6 shadow-2xl scale-in-center transition-colors duration-300 ${darkMode ? 'bg-slate-900' : 'bg-white'}`}>
            <h2 className={`text-xl font-bold mb-1 ${darkMode ? 'text-slate-100' : 'text-slate-800'}`}>Meta</h2>
            <p className="text-slate-500 text-xs mb-4">Ajuste o valor alvo da sua reserva.</p>
            <div className="space-y-4">
              <div className="relative">
                <input 
                  type="number" 
                  value={newGoalValue}
                  onChange={(e) => setNewGoalValue(e.target.value)}
                  className={`w-full px-4 py-3 border rounded-xl text-lg font-black outline-none transition-all ${darkMode ? 'bg-slate-800 border-slate-700 text-indigo-400 focus:border-indigo-500' : 'bg-slate-50 border-slate-200 text-indigo-600 focus:border-indigo-500'}`}
                  placeholder="0.00"
                />
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowGoalModal(false)} className={`flex-1 py-3 font-black uppercase text-[10px] tracking-widest rounded-xl ${darkMode ? 'text-slate-500 hover:bg-slate-800' : 'text-slate-500 hover:bg-slate-50'}`}>Voltar</button>
                <button onClick={handleUpdateGoal} className="flex-1 py-3 bg-indigo-600 text-white font-black uppercase text-[10px] tracking-widest rounded-xl shadow-lg">Salvar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Bottom Nav - Visível apenas no Mobile */}
      <nav className={`md:hidden fixed bottom-0 left-0 right-0 border-t px-8 py-3 flex justify-between items-center z-50 transition-colors duration-300 ${darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]'}`}>
        <button onClick={() => setActiveTab('overview')} className={`flex flex-col items-center gap-0.5 transition-colors ${activeTab === 'overview' ? 'text-indigo-500' : 'text-slate-400'}`}>
          <LayoutDashboard className="w-5 h-5" />
          <span className="text-[8px] font-bold uppercase tracking-tighter">Geral</span>
        </button>
        <button onClick={openEmptyForm} className="bg-indigo-600 w-11 h-11 rounded-full flex items-center justify-center text-white shadow-lg -mt-8 border-4 border-slate-50 dark:border-slate-950 active:scale-90 transition-transform">
          <Plus className="w-5 h-5" />
        </button>
        <button onClick={() => setActiveTab('reports')} className={`flex flex-col items-center gap-0.5 transition-colors ${activeTab === 'reports' ? 'text-indigo-500' : 'text-slate-400'}`}>
          <BarChart3 className="w-5 h-5" />
          <span className="text-[8px] font-bold uppercase tracking-tighter">Docs</span>
        </button>
      </nav>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.9); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @media (max-width: 380px) { .xs\\:hidden { display: none; } }
      `}</style>
    </div>
  );
};

export default App;
